mapper.update:
update user_addresses set name=#{req.name},detail=#{req.detail},lng=#{req.lng},lat=#{req.lat},
contact_name=#{req.contactName},contact_phone=#{req.contactPhone},updated_at=now()
where id=#{req.id} and user_id=#{userId}

mapper.select:
select o.id,o.user_id userId,o.driver_id driverId,o.start_address startAddress,o.end_address endAddress,o.appointment_time appointmentTime,
o.final_amount finalAmount,o.status,o.payment_status paymentStatus,o.created_at createdAt,d.real_name driverName,vt.name vehicleTypeName from move_orders o
left join drivers d on o.driver_id=d.id left join vehicle_types vt on o.vehicle_type_id=vt.id
where o.user_id=#{userId}
and o.status=#{status}
order by o.id desc

select o.id,o.user_id userId,o.driver_id driverId,o.start_address startAddress,o.end_address endAddress,o.appointment_time appointmentTime,
o.final_amount finalAmount,o.status,o.payment_status paymentStatus,o.created_at createdAt,vt.name vehicleTypeName from move_orders o left join vehicle_types vt on o.vehicle_type_id=vt.id
where o.driver_id=#{driverId}
and o.status=#{status}
order by o.id desc

select d.id,d.username,d.phone,d.real_name realName,d.vehicle_plate vehiclePlate,d.vehicle_type_id vehicleTypeId,d.service_area serviceArea,d.audit_status auditStatus,d.status,d.created_at createdAt,vt.name vehicleTypeName from drivers d left join vehicle_types vt on d.vehicle_type_id=vt.id
d.audit_status=#{auditStatus}
order by d.id desc
